 1	import { type Ref, useMemo, useState } from 'react';
 2	
 3	import {
 4	  MenuToggle,
 5	  type MenuToggleElement,
 6	  Select as PfSelect,
 7	  SelectList,
 8	  SelectOption,
 9	} from '@patternfly/react-core';
10	import { FilterIcon } from '@patternfly/react-icons';
11	import { useForkliftTranslation } from '@utils/i18n';
12	
13	import type { AttributeConfig } from '../utils/types';
14	
15	type FilterAttributeSelectProps<T> = {
16	  attributes: AttributeConfig<T>[];
17	  activeId?: string;
18	  onChange: (id: string) => void;
19	};
20	
21	const FilterAttributeSelect = <T,>({
22	  activeId,
23	  attributes,
24	  onChange,
25	}: FilterAttributeSelectProps<T>) => {
26	  const { t } = useForkliftTranslation();
27	  const [isOpen, setOpen] = useState(false);
28	
29	  const active = useMemo(
30	    () => attributes.find((a) => a.id === activeId) ?? attributes[0],
31	    [attributes, activeId],
32	  );
33	
34	  return (
35	    <PfSelect
36	      id="filter-attribute-select"
37	      isOpen={isOpen}
38	      selected={active?.id}
39	      onSelect={(_e, value) => {
40	        onChange(String(value));
41	        setOpen(false);
42	      }}
43	      onOpenChange={(open) => {
44	        setOpen(open);
45	      }}
46	      toggle={(toggleRef: Ref<MenuToggleElement>) => (
47	        <MenuToggle
48	          ref={toggleRef}
49	          onClick={() => {
50	            setOpen((open) => !open);
51	          }}
52	          isExpanded={isOpen}
53	          icon={<FilterIcon />}
54	        >
55	          {active?.label ?? t('Select filter type')}
56	        </MenuToggle>
57	      )}
58	      shouldFocusToggleOnSelect
59	    >
60	      <SelectList>
61	        {attributes.map((attr) => (
62	          <SelectOption key={attr.id} value={attr.id}>
63	            {attr.label}
64	          </SelectOption>
65	        ))}
66	      </SelectList>
67	    </PfSelect>
68	  );
69	};
70	
71	export default FilterAttributeSelect;

